package jetbrains.mps.editor.spellcheck;

/*Generated by MPS */

import org.jetbrains.annotations.Nullable;
import org.jetbrains.annotations.NotNull;
import com.intellij.grazie.jlanguage.Lang;

public class NativeLanguageUtil {
  public enum Category {
    ARTICLE(),
    PREPOSITION(),
    CONJUNCTION(),
    PARTICLE(),
    OTHER()
  }

  public static Category getCategory(@Nullable String posTag, @NotNull Lang lang) {
    if (posTag == null || posTag.isEmpty()) {
      return Category.OTHER;
    }
    switch (lang.getShortDisplayName()) {
      case "English":
        return mapEnglish(posTag);
      case "Dutch":
        return mapDutch(posTag);
      case "German":
        return mapGerman(posTag);
      case "French":
        return mapFrench(posTag);
      case "Spanish":
        return mapSpanish(posTag);
      default:
        return Category.OTHER;
    }
  }

  private static Category mapEnglish(String tag) {
    if (tag.equals("DT")) {
      return Category.ARTICLE;
    }
    if (tag.equals("IN")) {
      return Category.PREPOSITION;
    }
    if (tag.equals("CC")) {
      return Category.CONJUNCTION;
    }
    if (tag.equals("RP") || tag.equals("PART")) {
      return Category.PARTICLE;
    }
    return Category.OTHER;
  }
  private static Category mapDutch(String tag) {
    if (tag.startsWith("LID")) {
      return Category.ARTICLE;
    }
    if (tag.startsWith("VNW")) {
      return Category.ARTICLE;
    }
    if (tag.startsWith("GET")) {
      return Category.ARTICLE;
    }
    if (tag.startsWith("VRZ")) {
      return Category.PREPOSITION;
    }
    if (tag.startsWith("BYW")) {
      return Category.CONJUNCTION;
    }
    if (tag.startsWith("VGW")) {
      return Category.CONJUNCTION;
    }
    if (tag.startsWith("PART")) {
      return Category.PARTICLE;
    }
    return Category.OTHER;
  }
  private static Category mapGerman(String tag) {
    // STTS Tagset
    if (tag.startsWith("ART")) {
      return Category.ARTICLE;
    }
    if (tag.startsWith("APP")) {
      return Category.PREPOSITION;
    }
    // APPR, APPRART, APPO
    if (tag.startsWith("PTK")) {
      return Category.PARTICLE;
    }
    if (tag.startsWith("ZUS")) {
      return Category.CONJUNCTION;
    }
    if (tag.startsWith("KON")) {
      return Category.CONJUNCTION;
    }
    // PTKZU, PTKNEG, etc.
    return Category.OTHER;
  }
  private static Category mapFrench(String tag) {
    if (tag.equals("DET")) {
      return Category.ARTICLE;
    }
    if (tag.equals("D f s")) {
      return Category.ARTICLE;
    }
    if (tag.equals("D e p")) {
      return Category.ARTICLE;
    }
    if (tag.startsWith("C")) {
      return Category.CONJUNCTION;
    }
    if (tag.equals("P")) {
      return Category.PREPOSITION;
    }
    if (tag.equals("PART")) {
      return Category.PARTICLE;
    }
    return Category.OTHER;
  }
  private static Category mapSpanish(String tag) {
    // EAGLES Tagset (DA=Article, SP=Preposition)
    if (tag.startsWith("DA") || tag.startsWith("DI")) {
      return Category.ARTICLE;
    }
    if (tag.startsWith("SP")) {
      return Category.PREPOSITION;
    }
    if (tag.startsWith("CC")) {
      return Category.CONJUNCTION;
    }
    return Category.OTHER;
  }
}
